SELECT athlete_id, SUM(result_score) AS total_score
FROM event_results
GROUP BY athlete_id;

SELECT COUNT(medal_id) 
FROM medals 
WHERE athlete_id = 1;

SELECT event_id
FROM team_events
WHERE team_size = 4;

SELECT a.name, a.gender, a.country, m.medal_type, m.edition
FROM athletes a
INNER JOIN medals m ON a.athlete_id = m.athlete_id;

SELECT COUNT(DISTINCT athlete_id) AS total_athletes
FROM participation
WHERE edition = 1900;
